const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || {};
const env = typeof $env !== 'undefined' ? $env : {};

function header(name) {
  const wanted = name.toLowerCase();
  for (const [key, value] of Object.entries(headers)) {
    if (key.toLowerCase() === wanted) return value;
  }
  return undefined;
}

const expectedSecret = env.DAGENT_SHORTCUT_SECRET || '';
const providedSecret = header('x-dagent-shortcut-secret') || '';
if (!expectedSecret || providedSecret !== expectedSecret) {
  throw new Error('invalid shortcut secret');
}

const requestId = header('cf-ray') || header('x-request-id') || `${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
const idempotencyKey = `watch-${$execution.id}-${requestId}`.slice(0, 160);
const payload = {...body};

if (!payload.intent && !payload.action && (payload.task || payload.text || payload.idea || payload.message || payload.Task)) {
  payload.intent = 'capture_idea';
}
if (!payload.task && (payload.text || payload.idea || payload.message || payload.Task)) {
  payload.task = payload.text || payload.idea || payload.message || payload.Task;
}
if (!payload.source) {
  payload.source = 'apple_watch';
}
if (payload.task && !payload.input_type) {
  payload.input_type = 'voice';
}
if (payload.task && !payload.idempotency_key) {
  payload.idempotency_key = idempotencyKey;
}

payload.wait_seconds = 0;

return [{ json: { payload, idempotency_key: payload.idempotency_key || idempotencyKey } }];

const job = $input.first().json || {};
const result = job.result || {};
let reply = String(result.last_message || job.error || '').trim();

if (!reply) {
  if (job.status === 'running' || job.status === 'queued') {
    reply = `Task started. Job ${job.id || ''}`.trim();
  } else if (job.status) {
    reply = String(job.status);
  } else {
    reply = 'Request received.';
  }
}

if (reply.length > 3500) {
  reply = `${reply.slice(0, 3500)}\n...[truncated]`;
}

return [{
  json: {
    ok: !job.error && job.status !== 'failed',
    status: job.status || 'unknown',
    reply,
    message: reply,
    job_id: job.id || null,
    worker: job.worker || null,
    intent: job.intent || null,
    code_server_url: result.code_server_url || null,
    workspace_path: result.workspace_path || null,
  },
}];
